    'Api.csproj': {'System.Text.Json': '10.0.1', 'Azure.Identity': '1.13.2'},
    'Worker.csproj': {'Microsoft.Extensions.Hosting': '8.0.1', 'System.Text.Json': '8.0.4', 'OpenTelemetry.Extensions.Hosting': '1.15.0'},
    'Shared.csproj': {'System.Text.Json': '10.0.1', 'Azure.Identity': '1.11.4'},
    'Tests.csproj': {'xunit': '2.9.3', 'System.Text.Json': '10.0.1'},
}

# Parse after
after_pkgs = {}
for proj in after.get('projects', []):
    pname = proj['path'].split('/')[-1]
    pkgs = {}
    for fw in proj.get('frameworks', []):
        for pkg in fw.get('topLevelPackages', []):
            pkgs[pkg['id']] = pkg['resolvedVersion']
    after_pkgs[pname] = pkgs

print('=== CHANGES ===')
changes = []
for proj in sorted(baseline.keys()):
    bp = baseline[proj]
    ap = after_pkgs.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'N/A')
        av = ap.get(pkg, 'N/A')
