for proj in sorted(baseline.keys()):
    bp = baseline[proj]
    ap = after_pkgs.get(proj, {})
    for pkg in sorted(bp.keys()):
        if bp[pkg] == ap.get(pkg):
            print(f'  {proj}: {pkg} {bp[pkg]}')
